INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$What is the largest, isolated geographic unit in the Oracle Cloud Infrastructure (OCI) physical hierarchy that contains one or more availability domains?$oci$, $oci$[{"id":"a","text":"A fault domain"},{"id":"b","text":"A region"},{"id":"c","text":"A compartment"},{"id":"d","text":"A tenancy"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$An OCI region is a localized geographic area containing one or more availability domains. Fault domains are groupings inside an availability domain; compartments and tenancies are logical (not physical) constructs.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/General/Concepts/regions.htm","label":"Oracle Docs — Regions and Availability Domains"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What is the largest, isolated geographic unit in the Oracle Cloud Infrastructure (OCI) physical hierarchy that contains one or more availability domains?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A customer wants every component of an application to survive the failure of a single data center within a region. Which OCI construct provides physically separate data centers within a single region?$oci$, $oci$[{"id":"a","text":"Fault domains"},{"id":"b","text":"Availability domains"},{"id":"c","text":"Compartments"},{"id":"d","text":"Tenancies"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Availability domains are isolated, fault-tolerant data centers within a region that do not share power, cooling, or network. Fault domains protect against failures within a single availability domain.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/General/Concepts/regions.htm","label":"Oracle Docs — Regions and Availability Domains"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A customer wants every component of an application to survive the failure of a single data center within a region. Which OCI construct provides physically separate data centers within a single region?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Within a single availability domain, what does a fault domain protect against?$oci$, $oci$[{"id":"a","text":"A full region outage"},{"id":"b","text":"Hardware and maintenance failures localized to a grouping of infrastructure inside the availability domain"},{"id":"c","text":"Loss of an entire availability domain"},{"id":"d","text":"A DNS resolution failure"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$A fault domain is a logical grouping of hardware within an availability domain. Distributing instances across fault domains protects against simultaneous hardware failure and against impact from planned AD-internal maintenance.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/General/Concepts/regions.htm","label":"Oracle Docs — Regions and Availability Domains"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Within a single availability domain, what does a fault domain protect against?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$Which OCI offering provides a set of resources that remain free of charge for as long as the tenancy exists, with no time limit?$oci$, $oci$[{"id":"a","text":"30-day Free Trial credits"},{"id":"b","text":"Always Free resources"},{"id":"c","text":"Pay As You Go"},{"id":"d","text":"Universal Credits"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Always Free resources (e.g. limited Autonomous Database, small compute instances, object storage) have no time limit. Free Trial credits expire after 30 days; PAYG and Universal Credits are paid models.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/FreeTier/freetier_topic-Always_Free_Resources.htm","label":"Oracle Docs — Oracle Cloud Free Tier"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which OCI offering provides a set of resources that remain free of charge for as long as the tenancy exists, with no time limit?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A company needs predictable, committed cloud spend with the flexibility to consume any eligible OCI service. Which purchasing model best fits?$oci$, $oci$[{"id":"a","text":"Pay As You Go only"},{"id":"b","text":"Universal Credits with an Annual or Monthly commitment"},{"id":"c","text":"Always Free resources"},{"id":"d","text":"Bring Your Own License only"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Universal Credits let customers commit to an amount of spend and consume any eligible OCI service against it, offering predictability with flexibility. PAYG bills purely on usage with no commitment.$oci$, $oci$[{"url":"https://www.oracle.com/cloud/pricing/","label":"Oracle — OCI Pricing"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A company needs predictable, committed cloud spend with the flexibility to consume any eligible OCI service. Which purchasing model best fits?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which document defines Oracle's commitments for availability, manageability, and performance of OCI services, and is unique in covering all three?$oci$, $oci$[{"id":"a","text":"The Service Limits page"},{"id":"b","text":"The OCI Service Level Agreement (SLA)"},{"id":"c","text":"The Shared Responsibility Model"},{"id":"d","text":"The Universal Credits agreement"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$OCI SLAs are notable for covering availability, manageability, and performance — most cloud SLAs cover only availability. Service limits and the shared responsibility model are separate concepts.$oci$, $oci$[{"url":"https://www.oracle.com/cloud/sla/","label":"Oracle — Cloud Service Level Agreements"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which document defines Oracle's commitments for availability, manageability, and performance of OCI services, and is unique in covering all three?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A new tenancy hits a soft limit on the number of compute instances it can launch. What is the correct first action?$oci$, $oci$[{"id":"a","text":"Open a new tenancy"},{"id":"b","text":"Request a service limit increase through a support request"},{"id":"c","text":"Switch to a different region permanently"},{"id":"d","text":"Delete the existing instances and re-create them"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Service limits are set per tenancy and can be raised by submitting a service limit increase request. Creating a new tenancy or deleting resources does not address the limit.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/General/Concepts/servicelimits.htm","label":"Oracle Docs — Oracle Support and Service Limits"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A new tenancy hits a soft limit on the number of compute instances it can launch. What is the correct first action?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 1, $oci$TRUE_FALSE$oci$::"QType", $oci$True or False: An OCI region can contain only one availability domain.$oci$, $oci$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only in Always Free tenancies"},{"id":"d","text":"Only for government regions"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$False. A region contains one OR more availability domains. Some regions have a single AD while others have three; the model supports more than one.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/General/Concepts/regions.htm","label":"Oracle Docs — Regions and Availability Domains"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$True or False: An OCI region can contain only one availability domain.$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$An architect is choosing where to deploy a latency-sensitive workload serving European users while meeting EU data residency rules. Which factor is the PRIMARY driver for selecting a specific OCI region?$oci$, $oci$[{"id":"a","text":"The number of fault domains per availability domain"},{"id":"b","text":"Data residency/compliance requirements and proximity to users"},{"id":"c","text":"The color of the region in the console"},{"id":"d","text":"The number of compartments allowed"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Region selection is primarily driven by data residency/regulatory requirements, latency/proximity to users, and service availability in that region. Fault domain count is fixed and not a selection driver.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/General/Concepts/regions.htm","label":"Oracle Docs — Regions and Availability Domains"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$An architect is choosing where to deploy a latency-sensitive workload serving European users while meeting EU data residency rules. Which factor is the PRIMARY driver for selecting a specific OCI region?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which statement best describes OCI's core value proposition compared with traditional on-premises infrastructure?$oci$, $oci$[{"id":"a","text":"It removes the need for any security configuration by the customer"},{"id":"b","text":"It provides on-demand, elastic, pay-for-use infrastructure that scales without large upfront capital expenditure"},{"id":"c","text":"It guarantees zero cost for all services"},{"id":"d","text":"It eliminates the need to choose a region"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Cloud computing converts capital expense to operating expense, providing elastic, on-demand, metered resources. Customers still share security responsibility and must select regions.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/GSG/Concepts/baremetalintro.htm","label":"Oracle Docs — OCI Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which statement best describes OCI's core value proposition compared with traditional on-premises infrastructure?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$In OCI IAM, what is a compartment primarily used for?$oci$, $oci$[{"id":"a","text":"Encrypting data at rest"},{"id":"b","text":"Logically organizing and isolating cloud resources for access control and billing"},{"id":"c","text":"Providing network connectivity between VCNs"},{"id":"d","text":"Storing audit logs"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Compartments are logical containers used to organize and isolate resources, apply IAM policies, and track cost. They are not encryption, networking, or logging constructs.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/compartments/managingcompartments.htm","label":"Oracle Docs — Managing Compartments"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$In OCI IAM, what is a compartment primarily used for?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which IAM construct grants permissions, and to which entities are permissions assigned in OCI?$oci$, $oci$[{"id":"a","text":"Policies grant permissions directly to individual users"},{"id":"b","text":"Policies grant permissions to groups (and dynamic groups), not directly to users"},{"id":"c","text":"Policies grant permissions to compartments only"},{"id":"d","text":"Policies grant permissions to regions"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$OCI policies grant permissions to groups or dynamic groups, never directly to individual users. Users obtain access by membership in a group referenced by a policy.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/policies.htm","label":"Oracle Docs — How Policies Work"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which IAM construct grants permissions, and to which entities are permissions assigned in OCI?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A policy statement reads: "Allow group NetAdmins to manage virtual-network-family in compartment Networking". What does the verb "manage" indicate?$oci$, $oci$[{"id":"a","text":"Read-only access to the resource"},{"id":"b","text":"The broadest set of permissions including create, update, and delete"},{"id":"c","text":"Permission to inspect resource metadata only"},{"id":"d","text":"Permission to use but not create resources"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$OCI policy verbs in increasing power are inspect, read, use, and manage. "manage" grants the full set of permissions for that resource family, including create/update/delete.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/policies.htm","label":"Oracle Docs — How Policies Work"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A policy statement reads: "Allow group NetAdmins to manage virtual-network-family in compartment Networking". What does the verb "manage" indicate?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$What is the OCI tenancy?$oci$, $oci$[{"id":"a","text":"A single compute instance"},{"id":"b","text":"The root compartment and secure, isolated partition where all OCI cloud resources for an organization are created"},{"id":"c","text":"A network gateway"},{"id":"d","text":"A billing invoice"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$The tenancy is the root compartment — the secure, isolated partition that Oracle provisions for an organization where all resources reside.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/overview.htm","label":"Oracle Docs — IAM Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What is the OCI tenancy?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A security team wants instances to call OCI APIs (e.g. read Object Storage) without storing user credentials on the instance. Which IAM feature should they use?$oci$, $oci$[{"id":"a","text":"A static API key embedded in user data"},{"id":"b","text":"A dynamic group plus a policy granting that dynamic group permissions (instance principals)"},{"id":"c","text":"A shared password vault file"},{"id":"d","text":"A federated SAML user per instance"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Instance principals let compute instances authenticate to OCI services. You define a dynamic group matching the instances and write a policy granting that dynamic group the needed permissions — no stored credentials.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/dynamicgroups/managingdynamicgroups.htm","label":"Oracle Docs — Managing Dynamic Groups"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A security team wants instances to call OCI APIs (e.g. read Object Storage) without storing user credentials on the instance. Which IAM feature should they use?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A company already manages employee identities in Microsoft Entra ID and wants those users to sign in to the OCI Console without separate IAM users. Which capability enables this?$oci$, $oci$[{"id":"a","text":"Network Security Groups"},{"id":"b","text":"Identity federation with an external identity provider"},{"id":"c","text":"A dynamic group"},{"id":"d","text":"A service gateway"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Federation establishes trust between OCI and an external IdP (e.g. Entra ID/Okta), letting existing enterprise users authenticate to OCI without duplicate IAM users.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/federation.htm","label":"Oracle Docs — Federating with Identity Providers"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A company already manages employee identities in Microsoft Entra ID and wants those users to sign in to the OCI Console without separate IAM users. Which capability enables this?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which control adds a second verification factor (such as a mobile authenticator) when a user signs in to the OCI Console?$oci$, $oci$[{"id":"a","text":"Compartment quotas"},{"id":"b","text":"Multifactor authentication (MFA)"},{"id":"c","text":"A security list"},{"id":"d","text":"A route table"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$MFA requires a second factor (e.g. an authenticator app) in addition to the password, significantly reducing the risk of compromised credentials.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Tasks/usingmfa.htm","label":"Oracle Docs — Managing Multifactor Authentication"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which control adds a second verification factor (such as a mobile authenticator) when a user signs in to the OCI Console?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$An organization wants a billing rollup for the Finance department's resources while keeping them isolated from Engineering. What is the recommended IAM design?$oci$, $oci$[{"id":"a","text":"Place all resources in the root tenancy and tag them"},{"id":"b","text":"Create separate compartments per department and write policies scoped to each compartment"},{"id":"c","text":"Create one group per resource"},{"id":"d","text":"Use a single shared admin user for both teams"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Compartments provide isolation plus per-compartment cost tracking and scoped policies. A compartment-per-department design supports both billing rollup and least-privilege access.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/compartments/managingcompartments.htm","label":"Oracle Docs — Managing Compartments"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$An organization wants a billing rollup for the Finance department's resources while keeping them isolated from Engineering. What is the recommended IAM design?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$TRUE_FALSE$oci$::"QType", $oci$True or False: In OCI, a group is a collection of users who all need the same type of access to a set of resources.$oci$, $oci$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only for federated users"},{"id":"d","text":"Only in the root compartment"}]$oci$::jsonb, $oci$["a"]$oci$::jsonb, $oci$True. A group is a collection of users with the same access needs; policies reference groups to grant that access.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/groups/managinggroups.htm","label":"Oracle Docs — Managing Groups"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$True or False: In OCI, a group is a collection of users who all need the same type of access to a set of resources.$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$Which statement about the location where an IAM policy is attached is correct?$oci$, $oci$[{"id":"a","text":"A policy attached at the tenancy (root) can grant access to resources in any compartment beneath it"},{"id":"b","text":"A policy can only ever be attached to the tenancy root"},{"id":"c","text":"A policy attached to a child compartment automatically grants access to the parent"},{"id":"d","text":"Policies cannot be attached to compartments at all"}]$oci$::jsonb, $oci$["a"]$oci$::jsonb, $oci$Policies can be attached to the tenancy or to a compartment. A tenancy-level policy can grant access across all compartments; a compartment-level policy is scoped to that compartment and its children, never the parent.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/policies.htm","label":"Oracle Docs — How Policies Work"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which statement about the location where an IAM policy is attached is correct?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$What is the principle of least privilege as applied to OCI IAM policy design?$oci$, $oci$[{"id":"a","text":"Grant every user manage on all resources to avoid blocking work"},{"id":"b","text":"Grant only the minimum permissions required for a group to perform its function"},{"id":"c","text":"Disable all policies and rely on network controls"},{"id":"d","text":"Use only the default Administrators group"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Least privilege means granting only the permissions a group needs (e.g. inspect/read instead of manage when sufficient), reducing the blast radius of compromised accounts.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/policies.htm","label":"Oracle Docs — How Policies Work"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What is the principle of least privilege as applied to OCI IAM policy design?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A dynamic group is defined with the matching rule based on which attribute of OCI resources?$oci$, $oci$[{"id":"a","text":"The resource's public IP address"},{"id":"b","text":"Matching rules on resource attributes such as instance OCID, compartment OCID, or tags"},{"id":"c","text":"The resource's DNS name only"},{"id":"d","text":"The user's email domain"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Dynamic groups use matching rules over resource attributes (e.g. instance.compartment.id, tag values) so that resources like compute instances or functions become principals for policy.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/dynamicgroups/managingdynamicgroups.htm","label":"Oracle Docs — Managing Dynamic Groups"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A dynamic group is defined with the matching rule based on which attribute of OCI resources?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$Which default IAM group is created with full administrative privileges across the tenancy?$oci$, $oci$[{"id":"a","text":"NetworkAdmins"},{"id":"b","text":"Administrators"},{"id":"c","text":"Auditors"},{"id":"d","text":"Everyone"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$The Administrators group is created by default and has full access to all resources in the tenancy. Membership should be tightly controlled.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/overview.htm","label":"Oracle Docs — IAM Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which default IAM group is created with full administrative privileges across the tenancy?$oci$);
