INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which gateway allows resources in a public subnet to initiate connections to and receive connections from the public internet?$oci$, $oci$[{"id":"a","text":"NAT gateway"},{"id":"b","text":"Internet gateway"},{"id":"c","text":"Service gateway"},{"id":"d","text":"Dynamic routing gateway"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$An internet gateway provides bidirectional public internet connectivity for resources with public IPs in public subnets. A NAT gateway allows only outbound-initiated connections.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/overview.htm","label":"Oracle Docs — Connectivity Gateways"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which gateway allows resources in a public subnet to initiate connections to and receive connections from the public internet?$oci$);
