INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which gateway lets resources privately access Oracle services (such as Object Storage) without traversing the public internet?$oci$, $oci$[{"id":"a","text":"Internet gateway"},{"id":"b","text":"Service gateway"},{"id":"c","text":"NAT gateway"},{"id":"d","text":"Local peering gateway"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$A service gateway provides private connectivity from a VCN to supported Oracle services (e.g. Object Storage) so traffic stays on the Oracle network rather than the public internet.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/overview.htm","label":"Oracle Docs — Connectivity Gateways"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which gateway lets resources privately access Oracle services (such as Object Storage) without traversing the public internet?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$A company needs a dedicated, private, high-bandwidth connection between its on-premises data center and OCI that does not traverse the public internet. Which option should they choose?$oci$, $oci$[{"id":"a","text":"Site-to-Site VPN"},{"id":"b","text":"FastConnect"},{"id":"c","text":"Internet gateway"},{"id":"d","text":"NAT gateway"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$FastConnect provides a dedicated, private, consistent, high-bandwidth connection to OCI. Site-to-Site VPN is encrypted but rides over the public internet with variable performance.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/fastconnect.htm","label":"Oracle Docs — FastConnect Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A company needs a dedicated, private, high-bandwidth connection between its on-premises data center and OCI that does not traverse the public internet. Which option should they choose?$oci$);
