INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$What is the role of a Dynamic Routing Gateway (DRG) in OCI?$oci$, $oci$[{"id":"a","text":"It encrypts block volumes"},{"id":"b","text":"It is a virtual router providing a path for private traffic between a VCN and on-premises networks or other VCNs"},{"id":"c","text":"It distributes incoming web traffic across backends"},{"id":"d","text":"It stores DNS records"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$A DRG is a virtual router used to connect a VCN to on-premises networks (via VPN or FastConnect) and to other VCNs, enabling private routing.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingDRGs.htm","label":"Oracle Docs — Dynamic Routing Gateways"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What is the role of a Dynamic Routing Gateway (DRG) in OCI?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$A team wants to apply firewall rules to a specific set of VNICs regardless of their subnet, and update those rules in one place. Which OCI feature is the best fit?$oci$, $oci$[{"id":"a","text":"Security lists"},{"id":"b","text":"Network Security Groups (NSGs)"},{"id":"c","text":"Route tables"},{"id":"d","text":"DHCP options"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$NSGs are applied to individual VNICs and group them logically, independent of subnet, providing centrally managed, fine-grained virtual firewall rules. Security lists are applied at the subnet level.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/networksecuritygroups.htm","label":"Oracle Docs — Network Security Groups"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A team wants to apply firewall rules to a specific set of VNICs regardless of their subnet, and update those rules in one place. Which OCI feature is the best fit?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A security list rule controls traffic at which level by default?$oci$, $oci$[{"id":"a","text":"Per individual VNIC"},{"id":"b","text":"At the subnet level — applied to all VNICs in the subnet"},{"id":"c","text":"At the region level"},{"id":"d","text":"At the tenancy level"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Security lists act as a virtual firewall at the subnet level; their ingress/egress rules apply to all VNICs in the associated subnet. NSGs operate at the VNIC level.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/securitylists.htm","label":"Oracle Docs — Security Lists"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A security list rule controls traffic at which level by default?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which OCI service distributes incoming application traffic across multiple backend compute instances to improve availability and scale?$oci$, $oci$[{"id":"a","text":"Dynamic Routing Gateway"},{"id":"b","text":"Load Balancer"},{"id":"c","text":"Service gateway"},{"id":"d","text":"NAT gateway"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$The OCI Load Balancer distributes traffic across a backend set, performs health checks, and improves availability and horizontal scale of applications.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Balance/Concepts/balanceoverview.htm","label":"Oracle Docs — Load Balancer Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which OCI service distributes incoming application traffic across multiple backend compute instances to improve availability and scale?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$TRUE_FALSE$oci$::"QType", $oci$True or False: A public subnet and a private subnet can coexist within the same VCN.$oci$, $oci$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only across two VCNs"},{"id":"d","text":"Only in multi-AD regions"}]$oci$::jsonb, $oci$["a"]$oci$::jsonb, $oci$True. A VCN can contain both public and private subnets. Whether instances get public IPs depends on subnet type and routing/gateway configuration.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingVCNs_topic-Overview_of_VCNs_and_Subnets.htm","label":"Oracle Docs — VCNs and Subnets"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$True or False: A public subnet and a private subnet can coexist within the same VCN.$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$When designing a 3-tier web application, where should database servers typically be placed for security?$oci$, $oci$[{"id":"a","text":"In a public subnet with an internet gateway route"},{"id":"b","text":"In a private subnet with no direct internet ingress"},{"id":"c","text":"Outside any VCN"},{"id":"d","text":"In the tenancy root compartment only"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Backend/database tiers belong in private subnets with no inbound internet path, accessed only by the application tier. Public exposure of databases is a common security anti-pattern.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingVCNs_topic-Overview_of_VCNs_and_Subnets.htm","label":"Oracle Docs — VCNs and Subnets"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$When designing a 3-tier web application, where should database servers typically be placed for security?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$What does a route table in a VCN determine?$oci$, $oci$[{"id":"a","text":"Which users can log in"},{"id":"b","text":"How traffic leaving a subnet is directed to gateways or other targets"},{"id":"c","text":"How block volumes are encrypted"},{"id":"d","text":"The compute shape of an instance"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$A route table contains rules that direct egress traffic from a subnet to targets such as an internet gateway, NAT gateway, DRG, or service gateway.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingVCNs_topic-Overview_of_VCNs_and_Subnets.htm","label":"Oracle Docs — VCNs and Subnets"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What does a route table in a VCN determine?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$Which OCI Compute option provides a dedicated, single-tenant physical server with no virtualization layer managed by Oracle?$oci$, $oci$[{"id":"a","text":"Virtual machine (VM) instance"},{"id":"b","text":"Bare metal instance"},{"id":"c","text":"Container instance"},{"id":"d","text":"Function"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Bare metal instances give the customer an entire dedicated physical server with no Oracle hypervisor, ideal for performance-sensitive or licensing-sensitive workloads. VMs share physical hosts.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/Concepts/computeoverview.htm","label":"Oracle Docs — Compute Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which OCI Compute option provides a dedicated, single-tenant physical server with no virtualization layer managed by Oracle?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$What does a compute "shape" define for an instance?$oci$, $oci$[{"id":"a","text":"The instance's subnet and route table"},{"id":"b","text":"The number of OCPUs/CPUs, amount of memory, and other resources allocated to the instance"},{"id":"c","text":"The IAM policies applied to the instance"},{"id":"d","text":"The object storage bucket used by the instance"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$A shape determines the compute resources — OCPU/CPU count, memory, and (for some) network bandwidth — allocated to an instance. Networking and IAM are configured separately.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/References/computeshapes.htm","label":"Oracle Docs — Compute Shapes"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What does a compute "shape" define for an instance?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which compute shape type lets you independently select the number of OCPUs and the amount of memory to match a workload precisely?$oci$, $oci$[{"id":"a","text":"Fixed shapes"},{"id":"b","text":"Flexible shapes"},{"id":"c","text":"Dedicated shapes"},{"id":"d","text":"Preemptible shapes"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Flexible shapes (e.g. the Ampere A1 Flex / Standard Flex families) let you customize OCPU and memory independently, optimizing cost and fit. Fixed shapes have preset resources.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/References/computeshapes.htm","label":"Oracle Docs — Compute Shapes"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which compute shape type lets you independently select the number of OCPUs and the amount of memory to match a workload precisely?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A workload's demand varies through the day and the team wants instance count to grow and shrink automatically based on CPU utilization. Which feature should they configure?$oci$, $oci$[{"id":"a","text":"Custom images"},{"id":"b","text":"Autoscaling on an instance pool"},{"id":"c","text":"Bare metal instances"},{"id":"d","text":"A service gateway"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Autoscaling on an instance pool adds or removes instances based on metrics (e.g. CPU) or schedules, matching capacity to demand and controlling cost.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/Tasks/autoscalinginstancepools.htm","label":"Oracle Docs — Autoscaling"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A workload's demand varies through the day and the team wants instance count to grow and shrink automatically based on CPU utilization. Which feature should they configure?$oci$);
