INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which OCI service runs code in response to events without the customer provisioning or managing servers (serverless)?$oci$, $oci$[{"id":"a","text":"OCI Functions"},{"id":"b","text":"Bare metal instances"},{"id":"c","text":"Instance pools"},{"id":"d","text":"Block Volume"}]$oci$::jsonb, $oci$["a"]$oci$::jsonb, $oci$OCI Functions is a serverless, event-driven platform (based on the Fn project) where you deploy functions and pay only for execution — no server management.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Functions/Concepts/functionsoverview.htm","label":"Oracle Docs — OCI Functions Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which OCI service runs code in response to events without the customer provisioning or managing servers (serverless)?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 1, $oci$TRUE_FALSE$oci$::"QType", $oci$True or False: An OCPU on Oracle Cloud Infrastructure provides the equivalent compute capacity of one physical core.$oci$, $oci$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only for bare metal"},{"id":"d","text":"Only for Always Free"}]$oci$::jsonb, $oci$["a"]$oci$::jsonb, $oci$True. An OCPU (Oracle CPU) corresponds to physical core capacity. This differs from vendors that count hyper-threaded vCPUs as full CPUs.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/References/computeshapes.htm","label":"Oracle Docs — Compute Shapes"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$True or False: An OCPU on Oracle Cloud Infrastructure provides the equivalent compute capacity of one physical core.$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$To make a stateless web application resilient to a single data-center failure within a region, how should compute instances be distributed?$oci$, $oci$[{"id":"a","text":"All instances in one fault domain"},{"id":"b","text":"Across multiple availability domains (or fault domains in single-AD regions) behind a load balancer"},{"id":"c","text":"All instances in the tenancy root compartment"},{"id":"d","text":"In a single private subnet with no load balancer"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Spreading instances across availability domains (or fault domains when only one AD exists) behind a load balancer removes single points of failure and keeps the app available during a localized outage.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/Concepts/computeoverview.htm","label":"Oracle Docs — Compute Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$To make a stateless web application resilient to a single data-center failure within a region, how should compute instances be distributed?$oci$);
