INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Storage$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Multiple Linux compute instances need concurrent shared file access using the NFS protocol. Which OCI service should be used?$oci$, $oci$[{"id":"a","text":"Block Volume"},{"id":"b","text":"File Storage service"},{"id":"c","text":"Object Storage"},{"id":"d","text":"Archive Storage"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$The File Storage service provides a fully managed, shared NFS file system that many instances can mount concurrently — suited to shared application data.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/File/Concepts/filestorageoverview.htm","label":"Oracle Docs — File Storage Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Multiple Linux compute instances need concurrent shared file access using the NFS protocol. Which OCI service should be used?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Storage$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which Object Storage tier is designed for data that is rarely accessed and tolerates retrieval latency, at the lowest storage cost?$oci$, $oci$[{"id":"a","text":"Standard tier"},{"id":"b","text":"Archive tier"},{"id":"c","text":"Block tier"},{"id":"d","text":"Express tier"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Archive Storage offers the lowest cost for long-term, rarely accessed data; objects must be restored before download, introducing retrieval latency. Standard is for frequent access.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Archive/Concepts/archivestorageoverview.htm","label":"Oracle Docs — Archive Storage"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which Object Storage tier is designed for data that is rarely accessed and tolerates retrieval latency, at the lowest storage cost?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Storage$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A customer wants point-in-time copies of a block volume that can be used to restore or create new volumes. Which feature provides this?$oci$, $oci$[{"id":"a","text":"Object lifecycle policies"},{"id":"b","text":"Block volume backups (and clones)"},{"id":"c","text":"A service gateway"},{"id":"d","text":"A NAT gateway"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Block Volume backups create point-in-time snapshots stored in Object Storage; you can restore them or create new volumes. Clones create an immediate copy of a volume.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Block/Concepts/blockvolumebackups.htm","label":"Oracle Docs — Backing Up a Volume"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A customer wants point-in-time copies of a block volume that can be used to restore or create new volumes. Which feature provides this?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Storage$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$An application stores objects that are accessed frequently for 30 days and then rarely. Which Object Storage capability automatically reduces cost over time?$oci$, $oci$[{"id":"a","text":"Manually deleting objects each month"},{"id":"b","text":"Object Storage lifecycle policy rules that transition objects to Archive or delete them after a defined period"},{"id":"c","text":"Increasing the block volume size"},{"id":"d","text":"Adding a load balancer"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Object lifecycle management rules automatically transition objects to Archive or delete them after a set number of days, optimizing storage cost without manual effort.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Object/Concepts/understandingstoragetiers.htm","label":"Oracle Docs — Object Storage Tiers"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$An application stores objects that are accessed frequently for 30 days and then rarely. Which Object Storage capability automatically reduces cost over time?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Storage$oci$, 1, $oci$TRUE_FALSE$oci$::"QType", $oci$True or False: Block volumes can persist independently of the compute instance they were attached to.$oci$, $oci$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only for bare metal"},{"id":"d","text":"Only in Always Free"}]$oci$::jsonb, $oci$["a"]$oci$::jsonb, $oci$True. A block volume has a lifecycle independent of any instance — it can be detached and reattached to another instance, and data persists after instance termination.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Block/Concepts/overview.htm","label":"Oracle Docs — Block Volume Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$True or False: Block volumes can persist independently of the compute instance they were attached to.$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Storage$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$By default, how does OCI protect data at rest in Block Volume, Object Storage, and File Storage?$oci$, $oci$[{"id":"a","text":"It does not encrypt data at rest by default"},{"id":"b","text":"Data is encrypted at rest by default using Oracle-managed keys (with the option to use customer-managed keys in Vault)"},{"id":"c","text":"Only Object Storage is encrypted"},{"id":"d","text":"Encryption requires a paid add-on"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$OCI encrypts data at rest by default for Block, Object, and File storage using Oracle-managed keys; customers may instead supply their own keys via the Vault service.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Block/Concepts/overview.htm","label":"Oracle Docs — Block Volume Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P1$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$By default, how does OCI protect data at rest in Block Volume, Object Storage, and File Storage?$oci$);
