INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A workload must remain available even if one entire availability domain in a multi-AD region fails. What is the recommended design principle?$oci$, $oci$[{"id":"a","text":"Deploy everything in a single AD for lower latency"},{"id":"b","text":"Distribute redundant resources across multiple availability domains"},{"id":"c","text":"Use only fault domains within one AD"},{"id":"d","text":"Rely on a single bare metal instance"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$High availability across an AD failure requires distributing redundant components across multiple availability domains so the loss of one AD does not take down the workload.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/General/Concepts/regions.htm","label":"Oracle Docs — Regions and Availability Domains"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A workload must remain available even if one entire availability domain in a multi-AD region fails. What is the recommended design principle?$oci$);
