INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$Which characteristic best describes cloud computing elasticity in OCI?$oci$, $oci$[{"id":"a","text":"Resources are fixed at provisioning and cannot change"},{"id":"b","text":"Resources can be scaled up or down on demand to match workload needs"},{"id":"c","text":"Resources are only available in one region"},{"id":"d","text":"Resources require a multi-year contract"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Elasticity means provisioning and releasing resources on demand so capacity matches need, avoiding over-provisioning and reducing cost.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/GSG/Concepts/baremetalintro.htm","label":"Oracle Docs — OCI Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which characteristic best describes cloud computing elasticity in OCI?$oci$);
