INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$An organization must keep all data physically within one country to satisfy regulatory requirements. Which OCI capability primarily addresses this?$oci$, $oci$[{"id":"a","text":"Choosing a region located in that country (data residency)"},{"id":"b","text":"Adding more fault domains"},{"id":"c","text":"Using a larger compute shape"},{"id":"d","text":"Enabling autoscaling"}]$oci$::jsonb, $oci$["a"]$oci$::jsonb, $oci$Selecting an OCI region within the required country addresses data residency/sovereignty obligations. Fault domains, shapes, and autoscaling do not affect data location.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/General/Concepts/regions.htm","label":"Oracle Docs — Regions and Availability Domains"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$An organization must keep all data physically within one country to satisfy regulatory requirements. Which OCI capability primarily addresses this?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 1, $oci$TRUE_FALSE$oci$::"QType", $oci$True or False: OCI Service Level Agreements can cover not only availability but also manageability and performance.$oci$, $oci$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only availability is ever covered"},{"id":"d","text":"Only performance is covered"}]$oci$::jsonb, $oci$["a"]$oci$::jsonb, $oci$True. OCI is distinctive in offering SLAs that can cover availability, manageability, and performance, whereas many providers cover availability only.$oci$, $oci$[{"url":"https://www.oracle.com/cloud/sla/","label":"Oracle — Cloud Service Level Agreements"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$True or False: OCI Service Level Agreements can cover not only availability but also manageability and performance.$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which statement correctly distinguishes a region from an availability domain?$oci$, $oci$[{"id":"a","text":"A region is inside an availability domain"},{"id":"b","text":"A region is a geographic area that contains one or more availability domains (isolated data centers)"},{"id":"c","text":"They are synonyms"},{"id":"d","text":"An availability domain spans multiple regions"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$A region is a geographic area containing one or more availability domains. ADs are isolated data centers within a region and never span regions.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/General/Concepts/regions.htm","label":"Oracle Docs — Regions and Availability Domains"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which statement correctly distinguishes a region from an availability domain?$oci$);
