INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which OCI identifier is a globally unique ID assigned to every resource, user, and compartment?$oci$, $oci$[{"id":"a","text":"A CIDR block"},{"id":"b","text":"An OCID (Oracle Cloud Identifier)"},{"id":"c","text":"A MAC address"},{"id":"d","text":"A bucket name"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Every OCI resource has an OCID — a unique Oracle Cloud Identifier used to reference it in policies, APIs, and dynamic group rules.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/overview.htm","label":"Oracle Docs — IAM Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which OCI identifier is a globally unique ID assigned to every resource, user, and compartment?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A policy must let a group create and delete only object storage buckets and objects in one compartment. Which resource and verb scope is most appropriate?$oci$, $oci$[{"id":"a","text":"manage all-resources in tenancy"},{"id":"b","text":"manage object-family in that compartment"},{"id":"c","text":"inspect all-resources in tenancy"},{"id":"d","text":"read instance-family in that compartment"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Least privilege: grant manage on object-family scoped to the single compartment so the group can create/delete buckets/objects there only, not all resources tenancy-wide.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/policies.htm","label":"Oracle Docs — How Policies Work"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A policy must let a group create and delete only object storage buckets and objects in one compartment. Which resource and verb scope is most appropriate?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$Which IAM verb provides the LEAST access in an OCI policy statement?$oci$, $oci$[{"id":"a","text":"manage"},{"id":"b","text":"use"},{"id":"c","text":"read"},{"id":"d","text":"inspect"}]$oci$::jsonb, $oci$["d"]$oci$::jsonb, $oci$The verb hierarchy from least to most access is inspect, read, use, manage. "inspect" allows listing resources with the least detail.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/policies.htm","label":"Oracle Docs — How Policies Work"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which IAM verb provides the LEAST access in an OCI policy statement?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$What is the relationship between compartments and the tenancy?$oci$, $oci$[{"id":"a","text":"Compartments exist outside the tenancy"},{"id":"b","text":"The tenancy is the root compartment; other compartments are nested within it (hierarchically)"},{"id":"c","text":"Each compartment is a separate tenancy"},{"id":"d","text":"Compartments are network subnets"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$The tenancy is the root compartment. Additional compartments form a hierarchy nested under the root, enabling isolation and delegated administration.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/compartments/managingcompartments.htm","label":"Oracle Docs — Managing Compartments"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What is the relationship between compartments and the tenancy?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$A function needs to read secrets from OCI Vault. The team must avoid embedding credentials in the function. What is the correct approach?$oci$, $oci$[{"id":"a","text":"Hardcode an API key in the function code"},{"id":"b","text":"Add the function to a dynamic group and write a policy granting that dynamic group read access to the vault secrets (resource principals)"},{"id":"c","text":"Make the Vault public"},{"id":"d","text":"Disable IAM for the function"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Resource principals: a dynamic group matches the function, and a policy grants that dynamic group read on secret-family. No credentials are stored in code.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/dynamicgroups/managingdynamicgroups.htm","label":"Oracle Docs — Managing Dynamic Groups"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A function needs to read secrets from OCI Vault. The team must avoid embedding credentials in the function. What is the correct approach?$oci$);
