INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$What is the benefit of organizing resources into compartments rather than placing everything in the tenancy root?$oci$, $oci$[{"id":"a","text":"It increases network throughput"},{"id":"b","text":"It enables isolation, scoped access control, cost tracking, and delegated administration"},{"id":"c","text":"It encrypts data automatically"},{"id":"d","text":"It removes the need for IAM policies"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Compartments give logical isolation, scoped policies (least privilege), per-compartment cost visibility, and the ability to delegate administration — better governance than a flat root.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/compartments/managingcompartments.htm","label":"Oracle Docs — Managing Compartments"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What is the benefit of organizing resources into compartments rather than placing everything in the tenancy root?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$A group has a policy "Allow group Devs to read all-resources in compartment Dev". A developer cannot terminate an instance in compartment Dev. Why?$oci$, $oci$[{"id":"a","text":"The policy is attached to the wrong region"},{"id":"b","text":"The \"read\" verb does not include the permissions to delete/terminate resources; \"manage\" would be required"},{"id":"c","text":"Compartments cannot contain instances"},{"id":"d","text":"The user is not in any group"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$read grants viewing access but not create/update/delete. Terminating an instance requires manage on instance-family (use/manage level), not read.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/policies.htm","label":"Oracle Docs — How Policies Work"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A group has a policy "Allow group Devs to read all-resources in compartment Dev". A developer cannot terminate an instance in compartment Dev. Why?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$In OCI IAM, to what is a user typically added so that policies apply to them?$oci$, $oci$[{"id":"a","text":"A subnet"},{"id":"b","text":"One or more groups"},{"id":"c","text":"A route table"},{"id":"d","text":"A block volume"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Users are placed into groups; policies grant permissions to groups. A user inherits access through group membership.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/groups/managinggroups.htm","label":"Oracle Docs — Managing Groups"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$In OCI IAM, to what is a user typically added so that policies apply to them?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which IAM element is required to allow a compute instance itself (not a human user) to be authorized to call OCI services?$oci$, $oci$[{"id":"a","text":"A user password"},{"id":"b","text":"A dynamic group with a matching rule, referenced by a policy"},{"id":"c","text":"A NAT gateway"},{"id":"d","text":"A security list"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Dynamic groups make resources like instances principals. A matching rule selects the instances and a policy grants the dynamic group the needed permissions.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/dynamicgroups/managingdynamicgroups.htm","label":"Oracle Docs — Managing Dynamic Groups"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which IAM element is required to allow a compute instance itself (not a human user) to be authorized to call OCI services?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which statement about IAM policy inheritance in the compartment hierarchy is correct?$oci$, $oci$[{"id":"a","text":"A policy on a parent compartment can apply to resources in its child compartments"},{"id":"b","text":"Child compartments override parent permissions automatically"},{"id":"c","text":"Policies never apply below the compartment they are attached to"},{"id":"d","text":"Policies apply upward to the parent compartment"}]$oci$::jsonb, $oci$["a"]$oci$::jsonb, $oci$A policy attached to a compartment applies to that compartment and the compartments nested beneath it; it does not grant access to the parent.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/policies.htm","label":"Oracle Docs — How Policies Work"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which statement about IAM policy inheritance in the compartment hierarchy is correct?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$When creating a VCN, what must you define that determines the private IP address space available to its subnets?$oci$, $oci$[{"id":"a","text":"A compute shape"},{"id":"b","text":"One or more CIDR blocks"},{"id":"c","text":"A storage tier"},{"id":"d","text":"An IAM group"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$A VCN is defined with one or more CIDR blocks; subnets carve non-overlapping ranges from the VCN CIDR for private IP allocation.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingVCNs_topic-Overview_of_VCNs_and_Subnets.htm","label":"Oracle Docs — VCNs and Subnets"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$When creating a VCN, what must you define that determines the private IP address space available to its subnets?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which gateway should connect a VCN to another VCN in the SAME region using private IPs?$oci$, $oci$[{"id":"a","text":"Internet gateway"},{"id":"b","text":"Local Peering Gateway (LPG) or DRG-based local peering"},{"id":"c","text":"NAT gateway"},{"id":"d","text":"Service gateway"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Local VCN peering (via LPG or a DRG) connects two VCNs in the same region for private routing. Internet/NAT/service gateways do not peer VCNs.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/overview.htm","label":"Oracle Docs — Connectivity Gateways"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which gateway should connect a VCN to another VCN in the SAME region using private IPs?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A private instance must reach Oracle Object Storage without sending traffic over the public internet. Which gateway enables this?$oci$, $oci$[{"id":"a","text":"Internet gateway"},{"id":"b","text":"Service gateway"},{"id":"c","text":"Local peering gateway"},{"id":"d","text":"Dynamic routing gateway"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$A service gateway provides private access from the VCN to supported Oracle services such as Object Storage, keeping traffic off the public internet.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/overview.htm","label":"Oracle Docs — Connectivity Gateways"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A private instance must reach Oracle Object Storage without sending traffic over the public internet. Which gateway enables this?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$What primarily determines whether a subnet is "public" or "private" in OCI?$oci$, $oci$[{"id":"a","text":"The block volume attached to instances"},{"id":"b","text":"Whether instances in the subnet can be assigned public IP addresses (and routing to an internet gateway)"},{"id":"c","text":"The compartment it belongs to"},{"id":"d","text":"The compute shape used"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$A public subnet allows public IP assignment and typically routes to an internet gateway; a private subnet does not allow public IPs. The distinction is about public IP/Internet reachability.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingVCNs_topic-Overview_of_VCNs_and_Subnets.htm","label":"Oracle Docs — VCNs and Subnets"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What primarily determines whether a subnet is "public" or "private" in OCI?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$An enterprise needs consistent low-latency connectivity to OCI with a private circuit and predictable bandwidth for a data-migration project. Which is the best choice?$oci$, $oci$[{"id":"a","text":"Site-to-Site VPN over the internet"},{"id":"b","text":"FastConnect"},{"id":"c","text":"A public internet gateway"},{"id":"d","text":"A NAT gateway"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$FastConnect offers a private, dedicated connection with consistent latency and predictable bandwidth — preferable for large migrations versus internet-based VPN.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/fastconnect.htm","label":"Oracle Docs — FastConnect Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$An enterprise needs consistent low-latency connectivity to OCI with a private circuit and predictable bandwidth for a data-migration project. Which is the best choice?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which two OCI options can connect an on-premises network to a VCN? (Choose the answer listing both.)$oci$, $oci$[{"id":"a","text":"Internet gateway and NAT gateway"},{"id":"b","text":"Site-to-Site VPN and FastConnect (via a DRG)"},{"id":"c","text":"Service gateway and local peering gateway"},{"id":"d","text":"Security list and route table"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Hybrid connectivity to on-premises uses Site-to-Site VPN (IPSec over the internet) or FastConnect (private circuit), both attached to the VCN through a DRG.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingDRGs.htm","label":"Oracle Docs — Dynamic Routing Gateways"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which two OCI options can connect an on-premises network to a VCN? (Choose the answer listing both.)$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$What is the function of an OCI Load Balancer health check?$oci$, $oci$[{"id":"a","text":"It encrypts data at rest"},{"id":"b","text":"It monitors backend servers and stops routing traffic to unhealthy ones"},{"id":"c","text":"It assigns OCIDs to resources"},{"id":"d","text":"It manages IAM policies"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Load balancer health checks probe backends and remove unhealthy ones from rotation, sending traffic only to healthy instances for better availability.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Balance/Concepts/balanceoverview.htm","label":"Oracle Docs — Load Balancer Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What is the function of an OCI Load Balancer health check?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$A workload requires firewall rules that follow specific instances even when they are moved between subnets. Which feature satisfies this?$oci$, $oci$[{"id":"a","text":"Security lists (subnet-scoped)"},{"id":"b","text":"Network Security Groups (VNIC-scoped membership)"},{"id":"c","text":"Route tables"},{"id":"d","text":"DHCP options"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$NSGs group VNICs and apply rules to those members regardless of subnet, so the rules follow the instances. Security lists are tied to the subnet, not the instance.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/networksecuritygroups.htm","label":"Oracle Docs — Network Security Groups"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A workload requires firewall rules that follow specific instances even when they are moved between subnets. Which feature satisfies this?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which statement about security lists and NSGs is correct?$oci$, $oci$[{"id":"a","text":"They are identical and cannot be used together"},{"id":"b","text":"Security lists apply to all VNICs in a subnet; NSGs apply to a defined set of VNICs, and both can be used together"},{"id":"c","text":"Only one of them can exist per VCN"},{"id":"d","text":"NSGs apply to entire regions"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Security lists are subnet-level virtual firewalls; NSGs are VNIC-level. They can be combined, and a packet is allowed if permitted by the applicable rules of both.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/securitylists.htm","label":"Oracle Docs — Security Lists"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which statement about security lists and NSGs is correct?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$TRUE_FALSE$oci$::"QType", $oci$True or False: A NAT gateway allows instances in a private subnet to receive unsolicited inbound connections from the internet.$oci$, $oci$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only with a public IP"},{"id":"d","text":"Only in single-AD regions"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$False. A NAT gateway permits outbound-initiated connections only; it does not allow unsolicited inbound connections from the internet to private instances.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Concepts/overview.htm","label":"Oracle Docs — Connectivity Gateways"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$True or False: A NAT gateway allows instances in a private subnet to receive unsolicited inbound connections from the internet.$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$What is the purpose of a Dynamic Routing Gateway (DRG) attachment to a VCN?$oci$, $oci$[{"id":"a","text":"To attach block storage"},{"id":"b","text":"To provide the VCN a path for private traffic to on-premises networks or other VCNs/regions"},{"id":"c","text":"To create IAM users"},{"id":"d","text":"To define object storage lifecycle rules"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$A DRG is a virtual router; attaching it to a VCN enables private routing to on-premises (via VPN/FastConnect) and to other VCNs, including remote peering across regions.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingDRGs.htm","label":"Oracle Docs — Dynamic Routing Gateways"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What is the purpose of a Dynamic Routing Gateway (DRG) attachment to a VCN?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$Which OCI Load Balancer type provides a public entry point for internet-facing web traffic?$oci$, $oci$[{"id":"a","text":"A private load balancer with no public IP"},{"id":"b","text":"A public load balancer with a public IP address"},{"id":"c","text":"A NAT gateway"},{"id":"d","text":"A service gateway"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$A public load balancer has a public IP and accepts internet traffic, distributing it to backends. A private load balancer is reachable only within the VCN.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Balance/Concepts/balanceoverview.htm","label":"Oracle Docs — Load Balancer Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which OCI Load Balancer type provides a public entry point for internet-facing web traffic?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Networking$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$An application tier in a public subnet must talk to a database tier in a private subnet within the same VCN. What enables this communication by default?$oci$, $oci$[{"id":"a","text":"It is impossible without an internet gateway"},{"id":"b","text":"Instances in different subnets of the same VCN can route to each other via the VCN's local routing, subject to security rules"},{"id":"c","text":"A FastConnect circuit is required"},{"id":"d","text":"They must be in separate VCNs"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Subnets within the same VCN have local routing between them; communication is permitted as long as security lists/NSGs allow it. No internet gateway is needed for intra-VCN traffic.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Network/Tasks/managingVCNs_topic-Overview_of_VCNs_and_Subnets.htm","label":"Oracle Docs — VCNs and Subnets"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$An application tier in a public subnet must talk to a database tier in a private subnet within the same VCN. What enables this communication by default?$oci$);
