INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which OCI service is best suited to run short-lived, event-triggered code without managing any servers?$oci$, $oci$[{"id":"a","text":"OCI Functions"},{"id":"b","text":"Bare metal compute"},{"id":"c","text":"Block Volume"},{"id":"d","text":"A custom image"}]$oci$::jsonb, $oci$["a"]$oci$::jsonb, $oci$OCI Functions is serverless and event-driven; you deploy code and Oracle runs it on demand, billing per execution with no server management.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Functions/Concepts/functionsoverview.htm","label":"Oracle Docs — OCI Functions Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which OCI service is best suited to run short-lived, event-triggered code without managing any servers?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$An e-commerce site sees predictable traffic spikes every evening. Which approach scales capacity automatically and cost-effectively?$oci$, $oci$[{"id":"a","text":"Manually launching instances each evening"},{"id":"b","text":"Schedule-based autoscaling on an instance pool"},{"id":"c","text":"Using a single large bare metal server permanently"},{"id":"d","text":"Disabling the load balancer at night"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Schedule-based autoscaling adds capacity ahead of predictable peaks and reduces it afterward, automating scale and minimizing cost versus permanent over-provisioning.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/Tasks/autoscalinginstancepools.htm","label":"Oracle Docs — Autoscaling"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P2$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$An e-commerce site sees predictable traffic spikes every evening. Which approach scales capacity automatically and cost-effectively?$oci$);
