INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Introduction$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$An application has users in both North America and Europe and must minimize latency for each group while honoring EU data residency for European user data. What is the best approach?$oci$, $oci$[{"id":"a","text":"Deploy only in one US region for everyone"},{"id":"b","text":"Deploy in regions close to each user base, keeping EU user data in an EU region to meet residency"},{"id":"c","text":"Use more fault domains in one region"},{"id":"d","text":"Use a larger shape in one region"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Multi-region deployment near each user base reduces latency, while placing EU data in an EU region satisfies data residency. Fault domains/shapes do not address geography or residency.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/General/Concepts/regions.htm","label":"Oracle Docs — Regions and Availability Domains"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$An application has users in both North America and Europe and must minimize latency for each group while honoring EU data residency for European user data. What is the best approach?$oci$);
