INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$What does IAM stand for in OCI, and what is its core purpose?$oci$, $oci$[{"id":"a","text":"Internet Access Management — controls VCN routing"},{"id":"b","text":"Identity and Access Management — controls who can access which resources and what actions they can perform"},{"id":"c","text":"Image and Application Manager — manages compute images"},{"id":"d","text":"Infrastructure Audit Module — records logs"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$IAM (Identity and Access Management) governs authentication and authorization — which identities can access which OCI resources and what they may do.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/overview.htm","label":"Oracle Docs — IAM Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What does IAM stand for in OCI, and what is its core purpose?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A policy reads "Allow group Auditors to inspect all-resources in tenancy". What can the Auditors group do?$oci$, $oci$[{"id":"a","text":"Create and delete any resource"},{"id":"b","text":"List/view resources with limited detail, but not modify them"},{"id":"c","text":"Only manage networking resources"},{"id":"d","text":"Nothing — inspect is not a valid verb"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$The inspect verb permits listing/viewing resources (limited detail) without the ability to create, update, or delete them — suitable for an auditor role.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/policies.htm","label":"Oracle Docs — How Policies Work"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A policy reads "Allow group Auditors to inspect all-resources in tenancy". What can the Auditors group do?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which best describes the purpose of a dynamic group in OCI?$oci$, $oci$[{"id":"a","text":"To group human users for billing"},{"id":"b","text":"To group OCI resources (like instances or functions) so they can be granted permissions as principals"},{"id":"c","text":"To define VCN subnets"},{"id":"d","text":"To store encryption keys"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Dynamic groups define matching rules over resources so those resources (e.g. compute instances, functions) become principals that policies can authorize.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/dynamicgroups/managingdynamicgroups.htm","label":"Oracle Docs — Managing Dynamic Groups"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which best describes the purpose of a dynamic group in OCI?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 1, $oci$SINGLE$oci$::"QType", $oci$Which is the correct order of IAM policy verbs from MOST to LEAST permissive?$oci$, $oci$[{"id":"a","text":"inspect, read, use, manage"},{"id":"b","text":"manage, use, read, inspect"},{"id":"c","text":"read, manage, inspect, use"},{"id":"d","text":"use, inspect, manage, read"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$From most to least permissive: manage, use, read, inspect. "manage" includes full create/update/delete; "inspect" is the most limited.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/policies.htm","label":"Oracle Docs — How Policies Work"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which is the correct order of IAM policy verbs from MOST to LEAST permissive?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$A team needs developers to deploy resources only in a "Dev" compartment and have no access elsewhere. What is the recommended design?$oci$, $oci$[{"id":"a","text":"Add developers to the Administrators group"},{"id":"b","text":"Create a Developers group and a policy granting manage on the needed resource families scoped to compartment Dev"},{"id":"c","text":"Give each developer a tenancy-wide manage policy"},{"id":"d","text":"Disable IAM policies entirely"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$A dedicated group plus a compartment-scoped policy (manage only the needed families in Dev) enforces least privilege without granting broader tenancy access.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/compartments/managingcompartments.htm","label":"Oracle Docs — Managing Compartments"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A team needs developers to deploy resources only in a "Dev" compartment and have no access elsewhere. What is the recommended design?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which capability lets an organization reuse its existing corporate identities (e.g. from an external IdP) to access OCI?$oci$, $oci$[{"id":"a","text":"Dynamic groups"},{"id":"b","text":"Identity federation"},{"id":"c","text":"Network security groups"},{"id":"d","text":"Service limits"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Identity federation trusts an external identity provider so corporate users authenticate with existing credentials, mapped to OCI groups for authorization.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/federation.htm","label":"Oracle Docs — Federating with Identity Providers"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which capability lets an organization reuse its existing corporate identities (e.g. from an external IdP) to access OCI?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Why is enabling MFA for privileged OCI users considered a best practice?$oci$, $oci$[{"id":"a","text":"It increases compute performance"},{"id":"b","text":"It adds a second authentication factor, reducing the risk from compromised passwords"},{"id":"c","text":"It removes the need for IAM policies"},{"id":"d","text":"It encrypts block volumes"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$MFA requires an additional factor beyond the password, so even a compromised password cannot by itself grant access — especially important for privileged accounts.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Tasks/usingmfa.htm","label":"Oracle Docs — Managing Multifactor Authentication"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Why is enabling MFA for privileged OCI users considered a best practice?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$TRUE_FALSE$oci$::"QType", $oci$True or False: In OCI, permissions are granted directly to individual users rather than to groups.$oci$, $oci$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only for federated users"},{"id":"d","text":"Only in the root compartment"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$False. OCI policies grant permissions to groups (or dynamic groups). Individual users gain access through group membership, not direct grants.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/policies.htm","label":"Oracle Docs — How Policies Work"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$True or False: In OCI, permissions are granted directly to individual users rather than to groups.$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 3, $oci$SINGLE$oci$::"QType", $oci$A policy is attached to compartment "Prod". Which resources does it govern?$oci$, $oci$[{"id":"a","text":"Resources in Prod and any compartments nested under Prod"},{"id":"b","text":"All resources in the entire tenancy including the parent"},{"id":"c","text":"Only resources in the tenancy root"},{"id":"d","text":"No resources, because policies cannot attach to compartments"}]$oci$::jsonb, $oci$["a"]$oci$::jsonb, $oci$A policy attached to a compartment applies to that compartment and its descendants. It does not extend up to the parent or unrelated compartments.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/Concepts/policies.htm","label":"Oracle Docs — How Policies Work"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$A policy is attached to compartment "Prod". Which resources does it govern?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$OCI Identity and Access Management$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$What is the main governance benefit of placing each environment (Dev, Test, Prod) in its own compartment?$oci$, $oci$[{"id":"a","text":"Faster network throughput between environments"},{"id":"b","text":"Isolation, environment-scoped access policies, and separate cost visibility per environment"},{"id":"c","text":"Automatic encryption of all data"},{"id":"d","text":"Elimination of the need for groups"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Per-environment compartments isolate resources, allow least-privilege scoped policies, and give per-environment cost tracking — strong governance and security.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Identity/compartments/managingcompartments.htm","label":"Oracle Docs — Managing Compartments"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What is the main governance benefit of placing each environment (Dev, Test, Prod) in its own compartment?$oci$);
