INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$What is the role of an instance pool in OCI Compute?$oci$, $oci$[{"id":"a","text":"It encrypts data at rest"},{"id":"b","text":"It provisions and manages a group of identical instances from an instance configuration as one unit"},{"id":"c","text":"It defines IAM policies"},{"id":"d","text":"It stores backups"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$An instance pool creates and manages a set of identical instances based on an instance configuration, enabling consistent scaling and lifecycle management.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/Tasks/autoscalinginstancepools.htm","label":"Oracle Docs — Autoscaling"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What is the role of an instance pool in OCI Compute?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 1, $oci$TRUE_FALSE$oci$::"QType", $oci$True or False: A bare metal instance gives the customer a dedicated physical server without an Oracle-managed hypervisor.$oci$, $oci$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only in Always Free"},{"id":"d","text":"Only for Windows"}]$oci$::jsonb, $oci$["a"]$oci$::jsonb, $oci$True. Bare metal provides an entire dedicated physical server with no Oracle hypervisor — useful for performance or licensing constraints. VMs are virtualized.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/Concepts/computeoverview.htm","label":"Oracle Docs — Compute Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$True or False: A bare metal instance gives the customer a dedicated physical server without an Oracle-managed hypervisor.$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Why might you place instances of the same tier in different fault domains?$oci$, $oci$[{"id":"a","text":"To increase object storage durability"},{"id":"b","text":"To reduce the chance that a single hardware failure or AD-internal maintenance affects all instances simultaneously"},{"id":"c","text":"To avoid using IAM policies"},{"id":"d","text":"To bypass security lists"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Spreading instances across the three fault domains lowers the risk that one hardware failure or maintenance event takes down the whole tier within an AD.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Compute/References/computeshapes.htm","label":"Oracle Docs — Compute Shapes"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Why might you place instances of the same tier in different fault domains?$oci$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Compute$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$Which statement best characterizes the serverless model offered by OCI Functions?$oci$, $oci$[{"id":"a","text":"Customers must patch and scale the underlying servers"},{"id":"b","text":"The platform automatically runs and scales the code on demand; you focus only on the function logic"},{"id":"c","text":"It requires a permanent bare metal reservation"},{"id":"d","text":"It cannot be triggered by events"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$With OCI Functions, the platform handles server provisioning, scaling, and availability; developers provide only the code, which runs on demand (often event-triggered).$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Functions/Concepts/functionsoverview.htm","label":"Oracle Docs — OCI Functions Overview"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$Which statement best characterizes the serverless model offered by OCI Functions?$oci$);
