INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $oci$Storage$oci$, 2, $oci$SINGLE$oci$::"QType", $oci$What is the difference between a block volume backup and a block volume clone?$oci$, $oci$[{"id":"a","text":"They are identical operations"},{"id":"b","text":"A backup is a point-in-time copy stored in Object Storage for restore; a clone is an immediately usable copy of the volume"},{"id":"c","text":"A clone deletes the source volume"},{"id":"d","text":"A backup attaches directly as a new boot volume instantly"}]$oci$::jsonb, $oci$["b"]$oci$::jsonb, $oci$Backups are point-in-time copies kept in Object Storage and used to restore/create volumes; clones create an immediately usable independent copy of the volume.$oci$, $oci$[{"url":"https://docs.oracle.com/en-us/iaas/Content/Block/Concepts/blockvolumebackups.htm","label":"Oracle Docs — Backing Up a Volume"}]$oci$::jsonb, $oci$PUBLISHED$oci$::"QStatus", $oci$manual:oci-foundations-seed$oci$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $oci$1Z0-1085-P3$oci$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $oci$What is the difference between a block volume backup and a block volume clone?$oci$);
